3	export function nextGeneration(cells: Cell[]): Cell[] {
4	  const living = new Set<string>();
5	  for (const [x, y] of cells) {
6	    living.add(`${x},${y}`);
7	  }
8	
9	  const neighborCounts = new Map<string, number>();
10	
11	  for (const [x, y] of cells) {
12	    for (let dx = -1; dx <= 1; dx++) {
13	      for (let dy = -1; dy <= 1; dy++) {
14	        if (dx === 0 && dy === 0) continue;
15	        const key = `${x + dx},${y + dy}`;
16	        neighborCounts.set(key, (neighborCounts.get(key) ?? 0) + 1);
17	      }
18	    }
19	  }
20	
21	  const next: Cell[] = [];
22	  for (const [key, count] of neighborCounts) {
23	    const isAlive = living.has(key);
24	    if ((isAlive && (count === 2 || count === 3)) || (!isAlive && count === 3)) {
25	      const [xStr, yStr] = key.split(',');
26	      next.push([Number(xStr), Number(yStr)]);
27	    }
28	  }
29	
30	  return next;
31	}
